#include <bits/stdc++.h>
using namespace std;

const int N=3e7+10;

int n,d[N],ans;
char s[N],t[N];

int main(){
    scanf("%s",s+1);
    t[0]='$';
    for(int i=1;s[i];i++){
        t[++n]=s[i];
        if(s[i+1]) t[++n]='#';
    }
    t[n+1]='?';
    int r=1,l=0;
    for(int i=1;i<=n;i++){
        if(i>r) d[i]=1;
        else d[i]=min(d[l+r-i],r-i+1);
        while(t[i-d[i]]==t[i+d[i]]) d[i]++;
        if(i+d[i]-1>r) r=i+d[i]-1,l=i-d[i]+1;
    }
    for(int i=1;i<=n;i++){
        if(t[i+d[i]-1]=='#') d[i]--;
        ans=max(ans,d[i]);
    }
    printf("%d",ans);
    return 0;
}
